INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00547', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '專業化警政模式是警政發展的重要議題，由於社會變遷與全球化效應，目前已經進入第三次的科技 工業革命的時代，在這個年代當中，下列何者是第三次專業化警政年代下應有的模式具體作為？', '["警察組織應該採用半軍事化結構，強調服從，才能確實執行警察的專業技能", "強調偵查實務與鑑識能力，善用各種偵訊測謊的技巧來進行辦案，展現警察專業", "透過長期訓練、再進行遴選、最後經由嚴格測驗並淘汰，才能篩選出符合專業化警政所需的人力", "應善用當代最新科技來進行犯罪預防及追緝工作，針對新型態犯罪擬定應變策略"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00548', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '問題導向的警政策略模式中，眾所皆知的就是S.A.R.A模式，問題解決的過程應包含掃描、分析、 反應及評估，下列針對該模式的敘述何者錯誤？', '["分析之目的係為了解問題的特性、成因、嚴重性與範圍，以及研擬解決之道", "評量是整個模式中最後階段，針對採取的策略進行評量，了解是否達成目的", "反應是在可能的解決方案當中，配合實務及分析結果，選擇最適當之策略", "掃描主要是蒐集相關資訊，加以深入研究，才能界定問題範圍"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00549', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '理性決策模式是由古典經濟學家所提倡，以有限度的理性與直覺來追求利益為目標，下列對於理 性決策模式實際執行過程的敘述何者錯誤？', '["決策者對於問題及目標都有清楚的認識且互不衝突，但執行上往往隱晦不明", "理性決策以追求組織最大利益為主，因此實際決策過程中所有決策者會有一致性的價值信念來 客觀進行決策", "理性決策模式實際執行上會因為時間、勞力及費用有限而干擾", "理性決策模式可以透過資料比對來進行各種理性思維分析，得以尋找出最佳方案，但在實際執 行過程當中未必能確實的執行"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00550', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '警察倫理是警政工作品質的基石，警察人員除了肩負社會治安的工作外，因面對的個體從警察系 統擴及到社會大眾，內部倫理與外部倫理有極大的可能產生衝突。Weimer與Vining提出倫理衝 突解決策略，下列何者對於倫理衝突處理模式與策略的敘述錯誤？', '["為了能夠解決衝突，採用妥協模式將能完美的解決衝突", "透過正式管道提出建議與表達異議，而非四處散播不實情況", "有意無意地洩漏相關機密，並從中阻礙破壞行動", "各種方式反應無效，提出辭呈離職"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00551', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '第三方警政是結合非犯罪的第三方參與犯罪預防及控制的活動，下列對於第三方警政的相關敘述 何者正確？', '["第三方警政的概念當中，第一方是指犯罪人，第二方是指警察，第三方則是指其他能夠防止或 控制犯罪的人", "第三方警政強調要求非違法的第三方來承擔犯罪預防與控制的責任，但其核心主導權仍然是警 察，方能指揮第三方來協助", "第三方警政除了鼓勵第三方民眾主動協助治安管理之外，還可以透過法律規範來強制第三方民 眾配合", "有了第三方警政的協助，情境犯罪預防策略不必繼續實施，因為全民皆警，犯罪無所遁形"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00552', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '政策制定者在構思政策方案時，對於每個政策方案都必須針對各個價值面向進行理性決策思維過 程，方能了解政策的可行性程度，下列何者不是政策可行性評估分析所考慮的價值面向？', '["政治", "效益", "法律", "時間"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00553', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '警察政策的規劃、執行與評估，其過程與結果影響警察組織甚鉅，警察組織是一個以達成社會秩 序維護與保障社會安全目標的行政團體，下列針對警察組織的敘述何者正確？', '["警察組織是一個擁有武力的執法團體，但由於工作有緊急性與危險性，為了保護民眾與自身的 安全，其裁量權自由度較高，以個人主義的領導為主", "警察組織是依據法律授權執法，同時也透過法律授權行政命令與規定來處理相關業務", "警察組織隸屬於內政部警政署，重大決策的最上層級為內政部部長", "警察組織中的幕僚層級是蒐集資料、提供意見以供決策層級參考，因此幕僚層級必須直接與民 眾接觸，才能了解民眾需求，進而提供意見"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00554', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '從1960年代末期開始，「被害者學」開始成為犯罪學中的一門特殊學科，警察跟犯罪被害者的 關係更是密不可分。針對警察對於被害者的支持與預防措施的敘述，下列何者錯誤？', '["被害者能夠提供案件偵查的關鍵訊息，而警察能夠儘量提供被害者犯罪案件的相關處理情形， 建立彼此的信任，有利被害者安定的感受", "強化警政作為，增加巡邏頻率與強度、預防被害宣導、推動社區警政等，對於被害者來說就是 良好的預防和保護措施", "警察應以更積極的態度來處理犯罪被害事件，像是確實簽發報案三聯單、快速處理案件、善意 提醒可能的風險訊息與協助資源，可降低重複被害的機會", "警察應依照職責範圍依法辦理，依照程序進行被害者的安置，以超然的專家角色處理犯罪現場， 不應感受被害者情緒的變化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00555', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '派出所的設置是警察執行勤務規劃下的重要據點，對於警察勤務紮根於社區各個角落有推波助瀾 的功用。下列對於派出所的敘述何者正確？', '["派出所是第一線的刑事司法單位，與地方有著緊密的鏈結關係，最適用於現代科技化的電腦統 計警政政策", "派出所24小時運作，與地方緊密結合，派出所員警深入地方、主動服務，與地方民眾建立信 任，可提升民眾心理上的安全感受", "派出所制度由美國倡用，隨後由日本將派出所的警察勤務政策引進臺灣，沿用至今", "派出所屬於專責警勤區制度，由於深入地方，因此員警負責各自的轄區，專業分工下，鮮少有 勞逸不均的現象"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00556', 'police-8b7f1efc', 'police-8b7f1efc-moex-111-bf57eeea', 'sub-police-8b7f1efc-04', NULL, 'single_choice', '「新冠肺炎疫情期間假投資詐騙不斷，內政部警政署表示越來越多詐騙集團為規避查緝，將非法 金流虛擬化，此類新型態洗錢手法已是警方未來打擊重點。」當警察機關進行重大決策時，理性 決策的思維流程最常運用在警察政策的擬定。上述的全國打詐政策，是屬於理性決策思維當中的 那個步驟？', '["確認問題", "執行與檢討", "擬定方案", "確定目標"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:15+00:00", "source_pdf_sha1": "ba3a434a0a92", "answer_pdf_sha1": "903975beb430", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "501", "s": "1110", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "警察政策與犯罪預防", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
